{
    "visualizations": {
        "viz_04KnOEt1": {
            "type": "splunk.table",
            "dataSources": {
                "primary": "ds_FA1pAfGK"
            },
            "title": "Overlapping MAC Pool Info: $mac_current_pool_name$",
            "options": {
                "count": 5,
                "showInternalFields": false,
                "columnFormat": {
                    "Overlapping Pool Names": {
                        "data": "> table | seriesByName(\"Overlapping Pool Names\") | formatByType(Overlapping_Pool_NamesColumnFormatEditorConfig)",
                        "rowColors": "> table | seriesByName(\"Overlapping Pool Names\") | pick(Overlapping_Pool_NamesRowColorsEditorConfig)",
                        "rowBackgroundColors": "> table | seriesByName(\"Overlapping Pool Names\") | matchValue(Overlapping_Pool_NamesRowBackgroundColorsEditorConfig)"
                    }
                }
            },
            "context": {
                "Overlapping_Pool_NamesColumnFormatEditorConfig": {
                    "string": {
                        "unitPosition": "after"
                    }
                },
                "Overlapping_Pool_NamesRowColorsEditorConfig": [
                    "#dc4e41"
                ],
                "Overlapping_Pool_NamesRowBackgroundColorsEditorConfig": [
                    {
                        "match": "",
                        "value": "#FE3A3A"
                    }
                ]
