        "viz_Gdy7TWkm": {
            "type": "splunk.table",
            "dataSources": {
                "primary": "ds_xpfLK2um"
            },
            "title": "ResourcePool Utilization Check",
            "options": {
                "columnFormat": {
                    "Status": {
                        "data": "> table | seriesByName(\"Status\") | formatByType(StatusColumnFormatEditorConfig)",
                        "rowColors": "> table | seriesByName('Status') | pick(StatusRowColorsEditorConfig)",
                        "rowBackgroundColors": "> table | seriesByName(\"Status\") | matchValue(StatusRowBackgroundColorsEditorConfig)"
                    }
                },
                "count": 5,
                "showInternalFields": false
            },
            "context": {
                "StatusColumnFormatEditorConfig": {
                    "string": {
                        "unitPosition": "after"
                    }
                },
                "StatusRowColorsEditorConfig": [
                    "#ffffff"
                ],
                "StatusRowBackgroundColorsEditorConfig": [
                    {
                        "match": "Exhausted",
                        "value": "#B52D05"
                    },
                    {
                        "match": "Near Capacity",
                        "value": "#C48E06"
                    },
                    {
                        "match": "Healthy",
                        "value": "#408503"
                    }
                ]
            },
            "description": "Displays each resource pool with its available percentage and a status indicator based on utilization:  Exhausted → UtilizationPct >= 100  Near Capacity → UtilizationPct >= 80  Healthy → all other cases"
        },
        "viz_q1ek2GZ6": {
