        "viz_MdGyPSVp": {
            "type": "splunk.linkgraph",
            "dataSources": {
                "primary": "ds_dSu6qpXG"
            },
            "title": "Overlapping IP Pool Linkage",
            "eventHandlers": [
                {
                    "type": "drilldown.setToken",
                    "options": {
                        "tokens": [
                            {
                                "token": "ip_current_pool_name",
                                "key": "row._Name.value"
                            }
                        ]
                    }
                }
            ],
            "options": {
                "nodeWidth": 200,
                "nodeHeight": 30,
                "nodeSpacingY": 20,
                "nodeSpacingX": 45,
                "nodeHighlightColor": "#D0C4F5",
                "resultLimit": 5000
            },
            "description": "Visualizes relationships and overlaps between IP pools, highlighting shared or conflicting IP addresses across multiple pools to help identify allocation issues."
        },
        "viz_HPdakevL": {
            "type": "splunk.linkgraph",
            "dataSources": {
                "primary": "ds_vNitADFW"
