    "dataSources": {
        "ds_FA1pAfGK": {
            "type": "ds.search",
            "options": {
                "queryParameters": {
                    "earliest": "-24h@h",
                    "latest": "now"
                },
                "query": "| inputlookup cisco_intersight_macpool_pools\n| where splunk_managed_lifecycle == \"PRESENT\"\n| search account_name IN ($pool_account_name$)\n| rename MacBlocks.MacBlocks.From as MacBlocks_From, MacBlocks.MacBlocks.To as MacBlocks_To\n\n| rename Moid as CurrentPoolMoid\n| join type=left CurrentPoolMoid [ | inputlookup cisco_intersight_server_profiles | where splunk_managed_lifecycle == \"PRESENT\"\r\n| eval CurrentPoolMoid = PolicyBucket.PolicyBucket.MacPool.Moid | rename Name as CurrentPoolServerProfileName, Moid as CurrentPoolServerProfileMoid, AssignedServer.Moid as CurrentPoolServerMoid | table CurrentPoolServerProfileName, CurrentPoolServerProfileMoid, CurrentPoolServerMoid, CurrentPoolMoid ]\n| join type=left CurrentPoolServerMoid [ | inputlookup cisco_intersight_compute_physicalsummaries | where splunk_managed_lifecycle == \"PRESENT\" | rename Moid as CurrentPoolServerMoid, Name as CurrentPoolServerName | table CurrentPoolServerMoid, CurrentPoolServerName ]\n\n| rename CurrentPoolMoid as Moid\n| ciscointersightpooloverlapcheck pool_type=\"macpool\"\n\n| where isnotnull(OverlappingMoids)\n| dedup Moid\n| search Name IN ($mac_current_pool_name$)\n| fillnull value=\"-\"\n\n| eval MacBlocks = MacBlocks_From . \" - \" . MacBlocks_To\n| rename CurrentPoolServerMoid as _ServerMoid, CurrentPoolServerProfileMoid as _ServerProfileMoid, CurrentPoolServerProfileName as \"Server Profile Name\", CurrentPoolServerName as \"Server Name\", OverlappingMoids as _OverlappingMoids, OverlappingRanges as \"Overlapping MAC Pool Range\", OverlappingNames as \"Overlapping Names\", OverlappingServerProfileName as \"Overlapping Server Profile Name\", OverlappingServerProfileMoid as _OverlappingServerProfileMoid, OverlappingServerMoid as _OverlappingServerMoid, OverlappingServerName as \"Overlapping Server Name\", MacBlocks as \"MAC Block Range\", account_name as \"Account Name\", Organization.Name as \"Organization Name\"\n\n| eval current_pool_details = \"Name: \" . Name\n    . \" , Mac Range: \" . 'MAC Block Range'\n    . \" , Profile: \" . 'Server Profile Name'\n    . \" , Server: \" . 'Server Name'\n    . \" , Org: \" . 'Organization Name'\n\n| eval overlapping_pool_details = \"Name: \" . 'Overlapping Names'\n    . \" , Mac Range: \" . 'Overlapping MAC Pool Range'\n    . \" , Profile: \" . 'Overlapping Server Profile Name'\n    . \" , Server: \" . 'Overlapping Server Name'\n    . \" , Org: \" . 'OverlappingOrganizationName'\n\n| makemv delim=\" , \" current_pool_details\n| makemv delim=\" , \" overlapping_pool_details\n\n| rename current_pool_details as \"Pool Details\", overlapping_pool_details as \"Overlapping Pool Details\"\n| table \"Account Name\", \"Organization Name\", \"Pool Details\", \"Overlapping Pool Details\", _OverlappingServerMoid"
            },
            "name": "Overlapping MAC Pool Objects"
        },
        "ds_HaWBnmA0": {
            "type": "ds.search",
            "options": {
                "queryParameters": {
                    "earliest": "-24h@h",
                    "latest": "now"
                },
                "query": "| inputlookup cisco_intersight_asset_targets\n| where splunk_managed_lifecycle == \"PRESENT\"\n| dedup account_name\n| table account_name"
            },
            "name": "Pool Account Name"
        },
        "ds_qJ5EZy0X_ds_FA1pAfGK": {
            "type": "ds.search",
            "options": {
                "queryParameters": {
                    "earliest": "-24h@h",
                    "latest": "now"
                },
                "query": "| inputlookup cisco_intersight_ippool_pools\n| where splunk_managed_lifecycle == \"PRESENT\"\n| search account_name IN ($pool_account_name$)\n| rename IpV4Blocks.IpV4Blocks.From as ipv4blocks_from, IpV4Blocks.IpV4Blocks.To as ipv4blocks_to, IpV6Blocks.IpV6Blocks.From as ipv6blocks_from, IpV6Blocks.IpV6Blocks.To as ipv6blocks_to\n\n| ciscointersightexpandipblocks\n\n| `convert_ipv4_num(ipv4blocks_from)`\n| `convert_ipv4_num(ipv4blocks_to)`\n\n| `ipv6_to_num(ipv6blocks_from)`\n| `ipv6_to_num(ipv6blocks_to)`\n\n| rename Moid as CurrentPoolMoid\n| join type=left CurrentPoolMoid [ | inputlookup cisco_intersight_server_profiles | where splunk_managed_lifecycle == \"PRESENT\"\n| eval CurrentPoolMoid = coalesce('PolicyBucket.PolicyBucket.InbandIpPool.Moid', 'PolicyBucket.PolicyBucket.OutOfBandIpPool.Moid') | rename Name as CurrentPoolServerProfileName, Moid as CurrentPoolServerProfileMoid, AssignedServer.Moid as CurrentPoolServerMoid | table CurrentPoolServerProfileName, CurrentPoolServerProfileMoid, CurrentPoolServerMoid, CurrentPoolMoid ]\n| join type=left CurrentPoolServerMoid [ | inputlookup cisco_intersight_compute_physicalsummaries | where splunk_managed_lifecycle == \"PRESENT\" | rename Moid as CurrentPoolServerMoid, Name as CurrentPoolServerName | table CurrentPoolServerMoid, CurrentPoolServerName ]\n\n| rename CurrentPoolMoid as Moid\n\n| ciscointersightpooloverlapcheck pool_type=\"ippool\"\n| dedup Moid\n| where isnotnull(OverlappingMoids)\n| search Name IN ($ip_current_pool_name$)\n\n| eval ipv4blocks = ipv4blocks_from . \" - \" . ipv4blocks_to\n| fillnull value=\"-\"\n| rename account_name as \"Account Name\", CurrentPoolServerMoid as _ServerMoid, CurrentPoolServerProfileMoid as _ServerProfileMoid, CurrentPoolServerProfileName as \"Server Profile Name\", CurrentPoolServerName as \"Server Name\", OverlappingMoids as _OverlappingMoids, OverlappingRanges as \"Overlapping Pool IP Range\", OverlappingNames as \"Overlapping Names\", OverlappingServerProfileName as \"Overlapping Server Profile Name\", OverlappingServerProfileMoid as _OverlappingServerProfileMoid, OverlappingServerMoid as _OverlappingServerMoid, OverlappingServerName as \"Overlapping Server Name\", ipv4blocks as \"IP Range\",  Organization.Name as \"Organization Name\"\n\n| eval current_pool_details = \"Name: \" . Name\n    . \" , IP Range: \" . 'IP Range'\n    . \" , Profile: \" . 'Server Profile Name'\n    . \" , Server: \" . 'Server Name'\n    . \" , Org:\" . 'Organization Name'\n\n| eval overlapping_pool_details = \"Name: \" . 'Overlapping Names'\n    . \" , IP Range: \" . 'Overlapping Pool IP Range'\n    . \" , Profile: \" . 'Overlapping Server Profile Name'\n    . \" , Server: \" . 'Overlapping Server Name'\n    . \" , Org: \" . 'OverlappingOrganizationName'\n\n| makemv delim=\" , \" current_pool_details\n| makemv delim=\" , \" overlapping_pool_details\n\n| rename current_pool_details as \"Pool Details\", overlapping_pool_details as \"Overlapping Pool Details\"\n| table \"Account Name\", \"Pool Details\", \"Overlapping Pool Details\", _OverlappingServerMoid"
            },
            "name": "Overlapping IP Pool Objects"
        },
        "ds_76otTsdZ_ds_FA1pAfGK": {
            "type": "ds.search",
            "options": {
                "queryParameters": {
                    "earliest": "-24h@h",
                    "latest": "now"
                },
                "query": "| inputlookup cisco_intersight_fcpool_pools\n| where splunk_managed_lifecycle == \"PRESENT\"\n| search PoolPurpose=WWNN\n| search account_name IN ($pool_account_name$)\n\n| rename IdBlocks.IdBlocks.From as MacBlocks_From, IdBlocks.IdBlocks.To as MacBlocks_To\n\n| rename Moid as CurrentPoolMoid\n| join type=left CurrentPoolMoid [ | inputlookup cisco_intersight_server_profiles | where splunk_managed_lifecycle == \"PRESENT\"\n| eval CurrentPoolMoid = PolicyBucket.PolicyBucket.WwnnPool.Moid | rename Name as CurrentPoolServerProfileName, Moid as CurrentPoolServerProfileMoid, AssignedServer.Moid as CurrentPoolServerMoid | table CurrentPoolServerProfileName, CurrentPoolServerProfileMoid, CurrentPoolServerMoid, CurrentPoolMoid ]\n| join type=left CurrentPoolServerMoid [ | inputlookup cisco_intersight_compute_physicalsummaries | where splunk_managed_lifecycle == \"PRESENT\" | rename Moid as CurrentPoolServerMoid, Name as CurrentPoolServerName | table CurrentPoolServerMoid, CurrentPoolServerName ]\n\n| rename CurrentPoolMoid as Moid\n| ciscointersightpooloverlapcheck pool_type=\"macpool\"\n\n| dedup Moid\n\n| where isnotnull(OverlappingMoids)\n\n| eval MacBlocks = MacBlocks_From . \" - \" . MacBlocks_To\n| search Name IN ($wwnn_current_pool_name$)\n| fillnull value=\"-\"\n| rename CurrentPoolServerMoid as _ServerMoid, CurrentPoolServerProfileMoid as _ServerProfileMoid, CurrentPoolServerProfileName as \"Server Profile Name\", CurrentPoolServerName as \"Server Name\", OverlappingMoids as _OverlappingMoids, OverlappingRanges as \"Overlapping Pool Range\", OverlappingNames as \"Overlapping Names\", OverlappingServerProfileName as \"Overlapping Server Profile Name\", OverlappingServerProfileMoid as _OverlappingServerProfileMoid, OverlappingServerMoid as _OverlappingServerMoid, OverlappingServerName as \"Overlapping Server Name\", MacBlocks as \"WWNN Block Range\", account_name as \"Account Name\",  Organization.Name as \"Organization Name\"\n\n| eval current_pool_details = \"Name: \" . Name\n    . \" , WWNN Range: \" . 'WWNN Block Range'\n    . \" , Profile: \" . 'Server Profile Name'\n    . \" , Server: \" . 'Server Name'\n    . \" , Org: \" . 'Organization Name'\n\n| eval overlapping_pool_details = \"Name: \" . 'Overlapping Names'\n    . \" , WWNN Range: \" . 'Overlapping Pool Range'\n    . \" , Profile: \" . 'Overlapping Server Profile Name'\n    . \" , Server: \" . 'Overlapping Server Name'\n    . \" , Org: \" . 'OverlappingOrganizationName'\n\n| makemv delim=\" , \" current_pool_details\n| makemv delim=\" , \" overlapping_pool_details\n\n| rename current_pool_details as \"Pool Details\", overlapping_pool_details as \"Overlapping Pool Details\"\n| table \"Account Name\", \"Pool Details\", \"Overlapping Pool Details\", _OverlappingServerMoid"
            },
            "name": "Overlapping WWNN Pool Objects"
        },
        "ds_Giz69y2u_ds_76otTsdZ_ds_FA1pAfGK": {
            "type": "ds.search",
            "options": {
                "queryParameters": {
                    "earliest": "-24h@h",
                    "latest": "now"
